    """The event type, must be `input_audio_buffer.append`."""
    audio: Annotated[str, Field(..., description="Base64-encoded audio bytes. This must be in the format specified by the  `input_audio_format` field in the session configuration. ")]
    """Base64-encoded audio bytes. This must be in the format specified by the  `input_audio_format` field in the session configuration. """

    class Config:
        extra = "ignore"

